import { useState } from 'react'

export default function App() {
  const [messages, setMessages] = useState([{ type: 'bot', text: '¡Hola 👋 Bienvenido a UNIBOL!\n\n¿Cuál es tu NIT?' }])
  const [userInput, setUserInput] = useState('')
  const [step, setStep] = useState('nit')
  const [userData, setUserData] = useState({})
  const [loading, setLoading] = useState(false)
  const [showPDF, setShowPDF] = useState(false)

  const handleSendMessage = () => {
    if (!userInput.trim()) return
    setMessages([...messages, { type: 'user', text: userInput }])
    setUserInput('')
    setLoading(true)
    setTimeout(() => { procesarMensaje(userInput); setLoading(false) }, 500)
  }

  const procesarMensaje = (input) => {
    let response = ''
    if (step === 'nit') {
      const nit = input.trim()
      if (DATOS[nit]) {
        setUserData({ nit, ...DATOS[nit] })
        response = `✓ ${DATOS[nit].nombre}\n\n1️⃣ Estados de Cuentas\n2️⃣ Retenciones Aplicadas\n3️⃣ Envío de Certificados`
        setStep('opcion')
      } else {
        response = '❌ NIT no encontrado'
      }
    } else if (step === 'opcion') {
      if (input === '1') {
        if (userData.estados?.length > 0) {
          response = `📊 ESTADOS DE CUENTAS (${userData.estados.length} registros)\n\n`
          userData.estados.slice(0, 5).forEach(e => {
            response += `Factura: ${e.numero_factura}\nFecha: ${e.fecha_documento}\nValor: $${Math.abs(e.valor_pagar).toLocaleString()}\n\n`
          })
          if (userData.estados.length > 5) response += `... y ${userData.estados.length - 5} registros más`
        } else {
          response = '❌ Sin estados'
        }
      } else if (input === '2') {
        if (userData.retenciones?.length > 0) {
          response = `💰 RETENCIONES (${userData.retenciones.length} registros)\n\n`
          userData.retenciones.slice(0, 5).forEach(r => {
            response += `${r.tipo}: ${r.indicador}\n$${Math.abs(r.valor).toLocaleString()}\n\n`
          })
          if (userData.retenciones.length > 5) response += `... y ${userData.retenciones.length - 5} registros más`
        } else {
          response = '❌ Sin retenciones'
        }
      } else if (input === '3') {
        setShowPDF(true)
        response = `📄 CERTIFICADOS\n\nDescarga el instructivo abajo`
      }
    }
    setMessages(prev => [...prev, { type: 'bot', text: response }])
  }

  return (
    <div style={{ minHeight: '100vh', background: '#f5f5f5', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px' }}>
      <div style={{ display: 'flex', flexDirection: 'column', height: '600px', width: '100%', maxWidth: '500px', background: '#fff', borderRadius: '12px', border: '1px solid #e0e0e0', overflow: 'hidden' }}>
        <div style={{ background: '#d32f2f', color: '#fff', padding: '1rem', textAlign: 'center', fontWeight: 600 }}>UNIBOL - Certificados</div>
        <div style={{ flex: 1, overflowY: 'auto', padding: '1rem', display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {messages.map((msg, idx) => <div key={idx} style={{ display: 'flex', justifyContent: msg.type === 'user' ? 'flex-end' : 'flex-start' }}><div style={{ maxWidth: '80%', padding: '10px 14px', borderRadius: '12px', background: msg.type === 'user' ? '#007bff' : '#e9ecef', color: msg.type === 'user' ? '#fff' : '#000', fontSize: '14px', whiteSpace: 'pre-wrap' }}>{msg.text}</div></div>)}
          {loading && <div style={{ padding: '10px', background: '#e9ecef', borderRadius: '12px' }}>Escribiendo...</div>}
        </div>
        {showPDF && <div style={{ padding: '8px', borderTop: '1px solid #e0e0e0', background: '#f0f0f0' }}><a href="/INSTRUCTIVO_PARA_GENERACION_DE_CERTIFICADOS_TRIBUTARIOS__1__4838.pdf" target="_blank" rel="noopener noreferrer" style={{ display: 'inline-block', background: '#d32f2f', color: '#fff', padding: '8px 12px', borderRadius: '6px', textDecoration: 'none', fontSize: '13px' }}>📥 Descargar PDF</a></div>}
        <div style={{ display: 'flex', gap: '8px', padding: '12px', borderTop: '1px solid #e0e0e0' }}>
          <input type="text" placeholder="NIT..." value={userInput} onChange={(e) => setUserInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()} style={{ flex: 1, border: '1px solid #d0d0d0', borderRadius: '24px', padding: '10px 16px' }} disabled={loading} />
          <button onClick={handleSendMessage} style={{ background: '#d32f2f', color: '#fff', border: 'none', borderRadius: '50%', width: '40px', height: '40px', cursor: 'pointer' }} disabled={loading}>➤</button>
        </div>
      </div>
    </div>
  )
}
